<?php
// Définition de la fonction récursive pour lister les dossiers et sous-dossiers
function listerDossiers($cheminBase, $prefixe = '') {
    $resultats = [];
    $dir = opendir($cheminBase);

    while (($fichier = readdir($dir)) !== false) {
        if ($fichier != '.' && $fichier != '..') {
            $cheminComplet = $cheminBase . '/' . $fichier;
            if (is_dir($cheminComplet)) {
                // Ajoute le chemin relatif du dossier au tableau de résultats
                $cheminRelatif = $prefixe . $fichier;
                $resultats[] = $cheminRelatif;
                // Fusion avec les sous-dossiers trouvés récursivement
                $sousDossiers = listerDossiers($cheminComplet, $cheminRelatif . '/');
                $resultats = array_merge($resultats, $sousDossiers);
            }
        }
    }

    closedir($dir);
    return $resultats;
}

// Chemin de base à partir duquel lister les dossiers
$cheminBase = "/Users/nathalie/Dropbox/PROJETS/";
$dossiers = listerDossiers($cheminBase);

// Génération des options HTML pour le select
$optionsHtml = '';
foreach ($dossiers as $dossier) {
    $dossierAffichage = str_replace('/', ' - ', rtrim($dossier, '/')); // Formatage pour l'affichage
    $optionsHtml .= "<option value=\"{$dossier}\">{$dossierAffichage}</option>\n";
}
